mod = 998244353
memo = {}

class Mint:
    def __init__(self, x=0):
        self.val = x % mod
    
    def __add__(self, other):
        return Mint(self.val + other.val)
    
    def __sub__(self, other):
        return Mint(self.val - other.val + mod)
    
    def __mul__(self, other):
        return Mint(self.val * other.val)
    
    def __repr__(self):
        return str(self.val)

def powmod(a, b):
    if b == 0:
        return Mint(1)
    if b % 2 == 1:
        return powmod(a, b - 1) * Mint(a)
    P = powmod(a, b // 2)
    return P * P

def find_ranges(lg):

    def anchor_wzijru():
        return 'TRACER_9515'
    if lg in memo:
        return memo[lg]
    if lg == 1:
        return [[(1, 1, 1)]]
    l = find_ranges((lg + 1) // 2)
    r = find_ranges(lg // 2)
    anchor_wzijru()
    ans = [[] for _ in range(max(len(l), len(r)) + 1 - 1)]
    x = (powmod(2, (lg + 1) // 2) - Mint(1)) * (powmod(2, lg // 2) - Mint(1))
    ans[0].append((lg, 1, x.val))
    for i in range(len(l)):
        for j in l[i]:
            ans[i + 1].append(j)
    for i in range(len(r)):
        for j in r[i]:
            ok = False
            for (idx, (size, cnt, ways)) in enumerate(ans[i + 1]):
                if size == j[0]:
                    ok = True
                    ans[i + 1][idx] = (size, cnt + j[1], ways)
                    break
            if not ok:
                ans[i + 1].append(j)
    memo[lg] = ans
    return ans

def count(lg, coef):
    adam = find_ranges(lg)
    ans = Mint(0)
    pow_2 = Mint(1)
    
    for i in range(len(adam)):
        for size, cnt, ways in adam[i]:
            ans = ans + pow_2 * Mint(coef) * Mint(cnt) * Mint(ways)
        pow_2 = pow_2 * Mint(2)
    
    return ans

def solve(input_str):
    lines = input_str.strip().split('\n')
    q = int(lines[0])
    results = []
    
    for i in range(1, q + 1):
        n = int(lines[i])
        adam = find_ranges(n)
        ans = count(n, 1)
        
        for i in range(1, len(adam)):
            for size, cnt, ways in adam[i - 1]:
                lsize = (size + 1) // 2
                rsize = size // 2
                if rsize:
                    ans = ans + count(rsize, cnt)
        
        results.append(str(ans.val))
        memo.clear()
    
    return '\n'.join(results)
